@contextmanager
def get_db_connection():
    """PostgreSQL数据库连接上下文管理器"""
    conn = None
    try:
        conn = psycopg2.connect(**POSTGRES_CONFIG)
        conn.autocommit = False
        yield conn
    except Exception as e:
        if conn:
            conn.rollback()
        raise Exception(f"数据库操作异常：{str(e)}")
    finally:
        if conn:
            conn.close()


